// traditional
function add(a, b) {
  return a + b;
}

// arrow, with a block body
const add2 = (a, b) => {
  return a + b;
};

// arrow, with an implicit return (no braces, no return keyword)
const add3 = (a, b) => a + b;

const nums = [1, 2, 3, 4];

const doubled = nums.map(n => n * 2);   // [2, 4, 6, 8]
const evens = nums.filter(n => n % 2 === 0); // [2, 4]

console.log(doubled, evens);

exercise.prompt:
Rewrite this function as a one-line arrow function with an implicit return:

```js
function greet(name) {
  return 'Hello, ' + name + '!';
}
```

exercise.solution:
const greet = name => 'Hello, ' + name + '!';

// or with a template literal:
const greet2 = name => `Hello, ${name}!`;
